// ============================================================
// WF-07: WAITLIST INTELIGENTE
// Cuando se cancela un turno, ofrece el slot al primero en espera
// ============================================================

const helpers = this.helpers;
const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
const WA_TOKEN = $env.META_WHATSAPP_TOKEN;
const PHONE_ID = '963190063548521';

const DIAS = ['Dom','Lun','Mar','Mié','Jue','Vie','Sáb'];
const MESES = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic'];
function argDate(d) { return new Date(d.getTime() - 3*60*60*1000); }
function fmtFechaLarga(d) { return `${DIAS[d.getUTCDay()]} ${d.getUTCDate()} de ${MESES[d.getUTCMonth()]}`; }

async function supaGet(t, p) { try { return await helpers.httpRequest({ method:'GET', url:`${SUPABASE_URL}/rest/v1/${t}`, qs:p||{}, headers:{'apikey':SUPABASE_KEY,'Authorization':`Bearer ${SUPABASE_KEY}`} }); } catch(e) { return []; } }
async function supaUpdate(t, f, d) { try { await helpers.httpRequest({ method:'PATCH', url:`${SUPABASE_URL}/rest/v1/${t}`, qs:f, headers:{'apikey':SUPABASE_KEY,'Authorization':`Bearer ${SUPABASE_KEY}`,'Content-Type':'application/json'}, body:JSON.stringify({...d,updated_at:new Date().toISOString()}) }); } catch(e) {} }
async function supaDelete(t, f) { try { await helpers.httpRequest({ method:'DELETE', url:`${SUPABASE_URL}/rest/v1/${t}`, qs:f, headers:{'apikey':SUPABASE_KEY,'Authorization':`Bearer ${SUPABASE_KEY}`} }); } catch(e) {} }
async function sendText(ph, tx) { try { await helpers.httpRequest({ method:'POST', url:`https://graph.facebook.com/v21.0/${PHONE_ID}/messages`, headers:{'Authorization':`Bearer ${WA_TOKEN}`,'Content-Type':'application/json'}, body:JSON.stringify({messaging_product:'whatsapp',to:ph,type:'text',text:{body:tx}}) }); } catch(e) {} }
async function sendButtons(ph, tx, btns) { try { await helpers.httpRequest({ method:'POST', url:`https://graph.facebook.com/v21.0/${PHONE_ID}/messages`, headers:{'Authorization':`Bearer ${WA_TOKEN}`,'Content-Type':'application/json'}, body:JSON.stringify({messaging_product:'whatsapp',to:ph,type:'interactive',interactive:{type:'button',body:{text:tx},action:{buttons:btns.slice(0,3).map(b=>({type:'reply',reply:{id:b.id,title:b.title.substring(0,20)}}))}}}) }); } catch(e) {} }

const data = $input.first().json;
const profId = data.profesionalId;
const cancelledSlotIso = data.cancelledSlotIso; // optional: the specific slot that was freed

if (!profId) return [{ json: { action: 'no_prof_id', skipped: true } }];

// Buscar primer paciente en waitlist para este profesional (no notificado)
const waiters = await supaGet('consultorio_waitlist', {
  profesional_id: `eq.${profId}`,
  notificado: 'eq.false',
  select: 'id,paciente_id,created_at',
  order: 'created_at.asc',
  limit: '1'
});

if (!waiters?.length) return [{ json: { action: 'no_waiters', profId } }];

const waiter = waiters[0];
const pac = await supaGet('consultorio_pacientes', { id: `eq.${waiter.paciente_id}`, select: 'nombre,telefono_wa' });
const prof = await supaGet('consultorio_profesionales', { id: `eq.${profId}`, select: 'nombre,especialidad' });

if (!pac?.[0]) return [{ json: { action: 'waiter_not_found', waiterId: waiter.id } }];

// Marcar como notificado
await supaUpdate('consultorio_waitlist', { id: `eq.${waiter.id}` }, { notificado: true });

// Generar booking token para que pueda elegir turno directamente
const bookingToken = Date.now().toString(36) + Math.random().toString(36).substring(2);
const N8N_BASE = $env.WEBHOOK_URL || $env.N8N_HOST || '';
const bookingUrl = `${N8N_BASE}/webhook/consultorio-turnos?token=${bookingToken}`;

// Actualizar conversacion del paciente con el booking token
await supaUpdate('consultorio_conversaciones', { telefono_wa: `eq.${pac[0].telefono_wa}` }, {
  estado: 'esperando_booking_web',
  contexto: {
    pacienteId: waiter.paciente_id,
    pacienteNombre: pac[0].nombre,
    profesionalId: profId,
    profesionalNombre: prof?.[0]?.nombre || '',
    especialidad: prof?.[0]?.especialidad || '',
    bookingToken: bookingToken
  }
});

// Notificar al paciente
let msg = `¡Hola ${pac[0].nombre.split(' ')[0]}! Se liberó un turno con ${prof?.[0]?.nombre || 'el profesional'} (${prof?.[0]?.especialidad || ''}).\n\n`;
msg += `Elegí tu horario acá:\n👉 ${bookingUrl}\n\n`;
msg += `¡Apurate que se puede ocupar!`;

await sendText(pac[0].telefono_wa, msg);

return [{ json: { action: 'waitlist_notified', waiterId: waiter.id, paciente: pac[0].nombre, profId } }];

